scwin.onUdcCompleted = async function () {
  if (scwin.wrkStDt == "") {
    udc_dptIntendDd.setInitDate(scwin.nowDt, scwin.nowDt);
  } else {
    udc_dptIntendDd.setInitDate(scwin.wrkStDt, scwin.wrkEndDt);
  }
  if (scwin.lobranCd == "") {
    acb_lobranCd.setValue(scwin.loUpperLobranCd);
  } else {
    acb_lobranCd.setValue(scwin.lobranCd);
  }
  if (scwin.cntrNo != "") {
    acb_noClsCd.setValue("C");
    em_cntrOdrNo.setValue(scwin.cntrNo);
    scwin.f_Retrieve();
  } else if (scwin.odrNo != "") {
    acb_noClsCd.setValue("O");
    em_cntrOdrNo.setValue(scwin.odrNo);
    scwin.f_Retrieve();
  } else {
    acb_noClsCd.setValue("O");
  }
};
