scwin.f_saveContainerCompositeCargoLinkInformation = async function () {
  ds_srch3.undo();
  let dsSeq = 0;
  let writtenCnt = 0;
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "combine") == 1) {
      if (ds_results.getCellData(i, "cntrSizCd") != 20) {
        await $c.win.alert($p, "Combine은 20feet 컨테이너만 가능합니다");
        ds_results.undoAll();
        return false;
      }
      if (dsSeq == 0) {
        dsSeq = dsSeq + 1;
        ds_srch3.set("lobranCd", acb_lobranCd.getValue());
        ds_srch3.set("selOdrNo", ds_results.getCellData(i, "odrNo"));
        ds_srch3.set("selCntrSeq", ds_results.getCellData(i, "cntrSeq"));
        ds_srch3.set("selWrkStpCd", ds_results.getCellData(i, "wrkStpCd"));
        ds_srch3.set("combYn", 1);
        writtenCnt++;
      } else {
        ds_srch3.set("selOdrNo2", ds_results.getCellData(i, "odrNo"));
        ds_srch3.set("selCntrSeq2", ds_results.getCellData(i, "cntrSeq"));
        ds_srch3.set("selWrkStpCd2", ds_results.getCellData(i, "wrkStpCd"));
        writtenCnt++;
      }
      if (writtenCnt > 2) {
        await $c.win.alert($p, "combine은 2개만 선택해야 합니다");
        ds_results.undoAll();
        return false;
      }
    }
  }
  if (writtenCnt == 1 || writtenCnt == 0) {
    await $c.win.alert($p, "선택 개수 오류입니다. combine은 2개 선택해야 합니다");
    ds_results.undoAll();
    return false;
  }
  let chk = await $c.gus.cfConfirmMsg($p, MSG_CM_CRM_001);
  if (chk) {
    await $c.sbm.execute($p, sbm_containerCompositeCargoLink);
    scwin.f_Retrieve();
  }
};
scwin.dataSetDebug = async function (dataSet, isDebug) {
  if (isDebug == true) {
    let obj = dataSet;
    let str = "[[[[" + obj.id + "]]]]]\n";
    for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
      let colCount = obj.getColumnCount();
      for (let dsCol = 0; dsCol < colCount; dsCol++) {
        let colId = obj.getColumnID(dsCol);
        str += "[" + colId + "] " + obj.getCellData(dsRow, colId) + ", ";
      }
      str += "\n\n";
    }
    await $c.win.alert($p, str);
  }
};
